/**
 * Drizzle schema for ModelArena.
 *
 * Conventions:
 * - UUIDv4 primary keys, generated by the DB (`defaultRandom()`).
 * - Timestamps: `timestamp with time zone`, default `now()` on insert.
 *   `updatedAt` is intentionally NOT auto-updated by Drizzle — callers
 *   MUST set it explicitly on every UPDATE. Explicit is safer than a
 *   magic trigger.
 * - Immutable vote log: votes are never deleted or updated. Ratings are
 *   derived from votes and can be recomputed from scratch at any time.
 * - No global models catalog. `campaign_models` stores provider ids
 *   per-campaign. Cross-campaign aggregation depends on string equality
 *   of `provider_model_id`, which is why the UI must pick from a fixed
 *   catalog (src/lib/models.ts) and never free-type.
 *
 * Voting structure (tournament-per-prompt):
 *   Each (participant, prompt) plays one tournament with a 4-model
 *   bracket. Battles:
 *     b1: seed[0] vs seed[1]
 *     b2: seed[2] vs seed[3]
 *     b3: winner(b1) vs winner(b2)     — decides #1 / #2
 *     b4: loser(b1)  vs loser(b2)      — decides #3 / #4
 *     b5: rematch of b3's pair, IFF b3 was tie/both_bad — breaks the
 *         top-of-podium deadlock. Otherwise skipped.
 *   On a b1/b2 tie, a coin flip picks the advancer. The chosen
 *   generation is recorded in votes.advanced_generation_id so the
 *   result is auditable after the fact.
 *
 * Ratings: Bradley-Terry MM, iterated to convergence (≤ 0.0001) or 200
 * iters max. Standard errors from Fisher information, CI = rating ±
 * 1.96·SE. Display scale: rating = 1000 + 400·log10(strength/mean).
 * Sample-size thresholds (hide/preliminary/stable) live as code
 * constants, not schema.
 */
import { sql } from 'drizzle-orm';
import {
  pgTable,
  pgEnum,
  text,
  uuid,
  timestamp,
  integer,
  boolean,
  numeric,
  jsonb,
  uniqueIndex,
  index,
} from 'drizzle-orm/pg-core';

export const campaignStatusEnum = pgEnum('campaign_status', [
  'draft',
  'active',
  'completed',
]);

/**
 * How voters identify themselves when starting a campaign:
 *   - 'anonymous'       UI shows only a "Start voting" button; email field
 *                       is hidden. Any email sent in the payload is ignored.
 *   - 'email_required'  Voter must enter a valid email to start.
 *   - 'hybrid'          Voter can either enter an email OR press the
 *                       "Vote as anonymous" button. Matches the pre-feature
 *                       behavior, so existing campaigns migrate to this.
 */
export const votingModeEnum = pgEnum('voting_mode', [
  'anonymous',
  'email_required',
  'hybrid',
]);

/**
 * Evaluation mode for a single prompt. Tournament is the legacy default;
 * every prompt created before the multi-mode migration is `tournament`.
 * The five additional modes ship over Plan 01 Phases 1–2:
 *   - 'slider'         per-model 1–N Likert score
 *   - 'approve_reject' per-model boolean pass/fail
 *   - 'best_of_n'      participant picks one model's output from all N
 *   - 'multi_axis'     per-model per-dimension scores against a rubric
 *   - 'qualitative'    per-model free-text feedback (no numeric signal)
 *
 * Stored on `prompts.mode`; mode-specific settings live in
 * `prompts.mode_config` (jsonb). Each mode has its own response table
 * (see slider_responses, approve_reject_responses, best_of_n_responses,
 * multi_axis_responses, qualitative_responses); the legacy tournament
 * path continues to write through `tournaments` + `votes`.
 */
export const promptModeEnum = pgEnum('prompt_mode', [
  'tournament',
  'slider',
  'approve_reject',
  'best_of_n',
  'multi_axis',
  'qualitative',
]);

export const modelRegistry = pgTable('model_registry', {
  id: uuid('id').primaryKey().defaultRandom(),
  providerModelId: text('provider_model_id').notNull().unique(),
  displayName: text('display_name').notNull(),
  enabled: boolean('enabled').notNull().default(true),
  legacy: boolean('legacy').notNull().default(false),
  createdAt: timestamp('created_at', { withTimezone: true })
    .notNull()
    .defaultNow(),
  updatedAt: timestamp('updated_at', { withTimezone: true })
    .notNull()
    .defaultNow(),
});

export const voteWinnerEnum = pgEnum('vote_winner', [
  'A',
  'B',
  'tie',
  'both_bad',
]);

export const tournamentStatusEnum = pgEnum('tournament_status', [
  'in_progress',
  'complete',
]);

export const bracketPositionEnum = pgEnum('bracket_position', [
  'b1',
  'b2',
  'b3',
  'b4',
  'b5',
]);

export const campaigns = pgTable(
  'campaigns',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    shareSlug: text('share_slug').notNull().unique(),
    name: text('name').notNull(),
    description: text('description').notNull().default(''),
    categories: text('categories').array().notNull().default([]),
    status: campaignStatusEnum('status').notNull().default('draft'),
    /**
     * Operator-controlled voter-identity policy. Default for NEW campaigns
     * is `anonymous` — lowest-friction; the cookie still provides stable
     * participant identity and dedup. Pre-feature campaigns get migrated
     * to `hybrid` to preserve existing "email optional" behavior.
     */
    votingMode: votingModeEnum('voting_mode').notNull().default('anonymous'),
    /**
     * Optional operator copy shown above the email field in
     * `email_required` and `hybrid` modes — e.g. "Use your @acme.com email
     * so we can count internal votes separately." Ignored when
     * voting_mode = 'anonymous'. Capped at 500 chars at the API layer.
     */
    emailPromptMessage: text('email_prompt_message'),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    closedAt: timestamp('closed_at', { withTimezone: true }),
    /** Soft-delete tombstone. NULL means live; non-NULL means the campaign
     *  is hidden from list/detail endpoints and queued for hard purge by
     *  the daily cron after a 30-day grace window. Vote/rating history is
     *  preserved until purge so analytics aren't disrupted by undo-able
     *  deletes. */
    deletedAt: timestamp('deleted_at', { withTimezone: true }),
  },
  // The list endpoint sorts by createdAt DESC; index that direction
  // explicitly so postgres uses it without an extra sort step.
  // The (deletedAt, createdAt) partial-index supports the soft-delete
  // filter (`WHERE deleted_at IS NULL ORDER BY created_at DESC`) without
  // an extra sort and lets the cron purge sweep efficiently.
  (t) => [
    index('campaigns_created_at').on(sql`${t.createdAt} desc`),
    index('campaigns_deleted_at').on(t.deletedAt, t.createdAt),
  ],
);

/**
 * `text` is the authoritative blob sent to the LLM at generation time.
 * When `structured` is non-null, it's the creator-intended breakdown of
 * that same prompt — rendered in the voter UI so instructions, source
 * material, and output format read distinctly instead of as one wall.
 * Legacy prompts predate the field and have `structured = null`; they
 * render from `text` as-is (with markdown + whitespace preserved).
 */
export interface PromptStructured {
  instructions: string;
  input?: string;
  outputFormat?: string;
}

/**
 * Per-mode settings for a prompt. Shape depends on `prompts.mode`:
 *
 *   tournament       → null (no config)
 *   slider           → { min, max, minLabel?, maxLabel? }
 *   approve_reject   → { approveLabel?, rejectLabel? }
 *   best_of_n        → {} (N equals the campaign's model count)
 *   multi_axis       → { dimensions: [{ key, label, min, max }] }
 *   qualitative      → { prompt?, required }
 *
 * Validation happens at the API layer — the jsonb column is intentionally
 * loose so new fields can land without migrations.
 */
export type PromptModeConfig =
  | null
  | { min: number; max: number; minLabel?: string; maxLabel?: string }
  | { approveLabel?: string; rejectLabel?: string }
  | Record<string, never>
  | {
      dimensions: Array<{
        key: string;
        label: string;
        min: number;
        max: number;
      }>;
    }
  | { prompt?: string; required: boolean };

export const prompts = pgTable(
  'prompts',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    orderIndex: integer('order_index').notNull(),
    text: text('text').notNull(),
    context: text('context'),
    structured: jsonb('structured').$type<PromptStructured>(),
    categoryTags: text('category_tags').array().notNull().default([]),
    /**
     * Per-prompt evaluation mode. Defaults to 'tournament' so every prompt
     * created before Plan 01 Phase 1 keeps the existing bracket behavior.
     * New prompts default to the last-used mode in the campaign creation
     * UI (client-side default, not schema-level).
     */
    mode: promptModeEnum('mode').notNull().default('tournament'),
    modeConfig: jsonb('mode_config').$type<PromptModeConfig>(),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [index('prompts_campaign_order').on(t.campaignId, t.orderIndex)],
);

export const campaignModels = pgTable(
  'campaign_models',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    providerModelId: text('provider_model_id').notNull(),
    displayName: text('display_name').notNull(),
    params: jsonb('params').notNull().default({}),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_campaign_model').on(t.campaignId, t.providerModelId),
  ],
);

/**
 * One row per (prompt, campaign_model). Retry overwrites (UPSERT).
 * `output` is null until the generation completes; `error` is non-null
 * if it failed. Both-null means queued but not yet started.
 */
export const generations = pgTable(
  'generations',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    campaignModelId: uuid('campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    output: text('output'),
    tokensIn: integer('tokens_in'),
    tokensOut: integer('tokens_out'),
    latencyMs: integer('latency_ms'),
    costUsd: numeric('cost_usd', { precision: 12, scale: 8 }),
    providerResponseId: text('provider_response_id'),
    error: text('error'),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    completedAt: timestamp('completed_at', { withTimezone: true }),
  },
  (t) => [uniqueIndex('uniq_prompt_model').on(t.promptId, t.campaignModelId)],
);

/**
 * One row per (cookie, campaign). Same cookie visiting two campaigns
 * creates two participant rows — that's intentional; group-agreement
 * metrics are computed within a campaign.
 */
export const participants = pgTable(
  'participants',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    cookieId: uuid('cookie_id').notNull(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    email: text('email'),
    startedAt: timestamp('started_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    finishedAt: timestamp('finished_at', { withTimezone: true }),
  },
  (t) => [
    uniqueIndex('uniq_cookie_campaign').on(t.cookieId, t.campaignId),
    // Supports the finishedParticipants count in buildCampaignDetail
    // (WHERE campaign_id = ? AND finished_at IS NOT NULL).
    index('participants_campaign_finished').on(t.campaignId, t.finishedAt),
  ],
);

/**
 * One tournament per (participant, prompt). `seedModelIds` is an ordered
 * array of exactly 4 campaign_model ids defining the bracket:
 *   b1: seed[0] vs seed[1]
 *   b2: seed[2] vs seed[3]
 *   b3/b4/b5: determined by outcomes.
 *
 * When the campaign has exactly 4 models, all participants get the same
 * seed (ordered by campaign_models.created_at). When >4, each tournament
 * samples 4 independently — coverage > explainability. When <4 models,
 * activation is rejected.
 *
 * `status` flips to 'complete' once the required battles for this
 * tournament are recorded. `completedAt` is set at the same time.
 */
export const tournaments = pgTable(
  'tournaments',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    participantId: uuid('participant_id')
      .notNull()
      .references(() => participants.id, { onDelete: 'cascade' }),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    seedModelIds: uuid('seed_model_ids').array().notNull(),
    status: tournamentStatusEnum('status').notNull().default('in_progress'),
    startedAt: timestamp('started_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    completedAt: timestamp('completed_at', { withTimezone: true }),
  },
  (t) => [
    uniqueIndex('uniq_tournament_participant_prompt').on(
      t.participantId,
      t.promptId,
    ),
  ],
);

/**
 * Immutable. Dedup is on (tournament_id, bracket_position): no
 * participant can vote at the same bracket position twice within a
 * tournament.
 *
 * `advancedGenerationId` is set for b1 and b2 rows to record the
 * generation that moved on to b3:
 *   - winner='A' → advancedGenerationId = generationAId
 *   - winner='B' → advancedGenerationId = generationBId
 *   - winner='tie'/'both_bad' → randomly chosen by the handler; stored
 *     verbatim so the result is auditable
 * Null at b3/b4/b5 (no downstream propagation).
 *
 * `sessionId` is a diagnostic tag — new UUID per /vote/:slug visit.
 * Useful for "how many battles did this participant do in one sitting."
 */
export const votes = pgTable(
  'votes',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    tournamentId: uuid('tournament_id')
      .notNull()
      .references(() => tournaments.id, { onDelete: 'cascade' }),
    participantId: uuid('participant_id')
      .notNull()
      .references(() => participants.id, { onDelete: 'cascade' }),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    sessionId: uuid('session_id').notNull(),
    bracketPosition: bracketPositionEnum('bracket_position').notNull(),
    generationAId: uuid('generation_a_id')
      .notNull()
      .references(() => generations.id),
    generationBId: uuid('generation_b_id')
      .notNull()
      .references(() => generations.id),
    winner: voteWinnerEnum('winner').notNull(),
    advancedGenerationId: uuid('advanced_generation_id').references(
      () => generations.id,
    ),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_vote_tournament_position').on(
      t.tournamentId,
      t.bracketPosition,
    ),
    index('votes_campaign').on(t.campaignId),
    index('votes_prompt').on(t.promptId),
    index('votes_participant').on(t.participantId),
  ],
);

// ===========================================================================
// Multi-mode response tables (Plan 01 Phase 0 — shipped empty; handlers
// populate them in Phase 1+). The legacy tournament stack above
// (tournaments + votes) is unaffected and continues to serve
// `mode='tournament'` prompts.
//
// Key invariants across all five:
//   - Keyed by (participant, prompt[, campaign_model]) depending on mode.
//   - Uniqueness prevents double-submission.
//   - `campaignId` denormalized on every row for cheap per-campaign scans
//     in the ratings pipeline.
//   - `sessionId` mirrors the tournament convention for diagnostics
//     (one UUID per /vote/:slug visit).
// ===========================================================================

/**
 * Slider mode: one numeric score per (participant, prompt, campaign_model).
 * Score range is determined by the prompt's mode_config.min/max; stored
 * here as a raw integer. Mean + variance per model is the aggregate.
 */
export const sliderResponses = pgTable(
  'slider_responses',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    participantId: uuid('participant_id')
      .notNull()
      .references(() => participants.id, { onDelete: 'cascade' }),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    campaignModelId: uuid('campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    sessionId: uuid('session_id').notNull(),
    score: integer('score').notNull(),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_slider_response').on(
      t.participantId,
      t.promptId,
      t.campaignModelId,
    ),
    index('slider_responses_campaign').on(t.campaignId),
    index('slider_responses_prompt').on(t.promptId),
  ],
);

/**
 * Approve/Reject mode: one boolean per (participant, prompt, campaign_model).
 * Pass rate per model is the aggregate; Wilson CI for confidence bounds.
 */
export const approveRejectResponses = pgTable(
  'approve_reject_responses',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    participantId: uuid('participant_id')
      .notNull()
      .references(() => participants.id, { onDelete: 'cascade' }),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    campaignModelId: uuid('campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    sessionId: uuid('session_id').notNull(),
    approved: boolean('approved').notNull(),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_approve_reject_response').on(
      t.participantId,
      t.promptId,
      t.campaignModelId,
    ),
    index('approve_reject_responses_campaign').on(t.campaignId),
    index('approve_reject_responses_prompt').on(t.promptId),
  ],
);

/**
 * Best-of-N mode: one chosen campaign_model per (participant, prompt).
 * Unlike the other response tables, this is keyed on (participant, prompt)
 * without the model_id — the participant sees all N and picks exactly one.
 * Win rate per model is the aggregate; binomial CI for bounds.
 */
export const bestOfNResponses = pgTable(
  'best_of_n_responses',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    participantId: uuid('participant_id')
      .notNull()
      .references(() => participants.id, { onDelete: 'cascade' }),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    chosenCampaignModelId: uuid('chosen_campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    sessionId: uuid('session_id').notNull(),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_best_of_n_response').on(t.participantId, t.promptId),
    index('best_of_n_responses_campaign').on(t.campaignId),
    index('best_of_n_responses_prompt').on(t.promptId),
  ],
);

/**
 * Multi-axis mode: per-dimension scores per (participant, prompt, model).
 * `scores` is a jsonb map: { [dimensionKey]: number }. Dimension keys
 * must match the prompt's mode_config.dimensions[].key (enforced at the
 * API layer). Per-dimension mean + variance per model is the aggregate.
 */
export interface MultiAxisScores {
  [dimensionKey: string]: number;
}

export const multiAxisResponses = pgTable(
  'multi_axis_responses',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    participantId: uuid('participant_id')
      .notNull()
      .references(() => participants.id, { onDelete: 'cascade' }),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    campaignModelId: uuid('campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    sessionId: uuid('session_id').notNull(),
    scores: jsonb('scores').$type<MultiAxisScores>().notNull(),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_multi_axis_response').on(
      t.participantId,
      t.promptId,
      t.campaignModelId,
    ),
    index('multi_axis_responses_campaign').on(t.campaignId),
    index('multi_axis_responses_prompt').on(t.promptId),
  ],
);

/**
 * Qualitative mode: free-text feedback per (participant, prompt, model).
 * No numeric aggregate — V1 exposes the raw text list; later an NLP
 * clustering pass surfaces themes. Text is optional at the row level
 * (the prompt's mode_config.required flag decides UI enforcement).
 */
export const qualitativeResponses = pgTable(
  'qualitative_responses',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    participantId: uuid('participant_id')
      .notNull()
      .references(() => participants.id, { onDelete: 'cascade' }),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    campaignModelId: uuid('campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    sessionId: uuid('session_id').notNull(),
    text: text('text').notNull(),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_qualitative_response').on(
      t.participantId,
      t.promptId,
      t.campaignModelId,
    ),
    index('qualitative_responses_campaign').on(t.campaignId),
    index('qualitative_responses_prompt').on(t.promptId),
  ],
);

/**
 * Denormalized per-category rating cache. Only GLOBAL ratings — personal
 * ratings are computed transiently on the results page.
 *
 * Category sentinel 'overall' represents the campaign aggregate; other
 * values are user-defined category tags.
 *
 * Columns:
 *   - `rating`      Display scale (1000-centered). Null until first
 *                   compute pass.
 *   - `seRating`    Standard error on the rating scale, from Fisher
 *                   information. Null until first compute.
 *   - `ciLow/High`  rating ± 1.96·seRating. Stored for read convenience.
 *   - `btStrength`  Raw B-T strength post-convergence, post-normalization.
 *                   Stored for debugging; not shown in UI.
 *   - `gameCount`   Number of comparisons contributing to this row.
 */
export const ratings = pgTable(
  'ratings',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    campaignModelId: uuid('campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    category: text('category').notNull().default('overall'),
    rating: integer('rating').notNull().default(1000),
    seRating: numeric('se_rating', { precision: 10, scale: 6 }),
    ciLow: integer('ci_low'),
    ciHigh: integer('ci_high'),
    btStrength: numeric('bt_strength', { precision: 12, scale: 8 }),
    gameCount: integer('game_count').notNull().default(0),
    computedAt: timestamp('computed_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_rating').on(
      t.campaignId,
      t.campaignModelId,
      t.category,
    ),
  ],
);

/**
 * Magic-link tokens for the email sign-in flow.
 *
 * We store `sha256(token_raw)` so a DB leak can't replay links. The raw
 * token lives only in the email body. Rows are single-use (marked via
 * `consumed_at`) and expire after 15 minutes. A nightly purge of
 * `expires_at < now() - interval '1 day'` would be reasonable; for now
 * the table is small enough to ignore.
 */
export const magicLinks = pgTable(
  'magic_links',
  {
    tokenHash: text('token_hash').primaryKey(),
    email: text('email').notNull(),
    expiresAt: timestamp('expires_at', { withTimezone: true }).notNull(),
    consumedAt: timestamp('consumed_at', { withTimezone: true }),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [index('magic_links_expires_at_idx').on(t.expiresAt)],
);

